import json
import re
from collections import Counter

import modal

APP_NAME = "document-analytics-pipeline"
VOLUME_NAME = "document-analytics-pipeline-vol"
DICT_NAME = "document-analytics-pipeline-output"
REPORT_PATH = "/reports/analytics_report.json"

image = modal.Image.debian_slim()
app = modal.App(APP_NAME)
volume = modal.Volume.from_name(VOLUME_NAME, create_if_missing=True)
output_dict = modal.Dict.from_name(DICT_NAME, create_if_missing=True)


@app.cls(image=image)
class DocumentAnalyzer:
    @modal.enter()
    def setup(self) -> None:
        self.word_pattern = re.compile(r"[A-Za-z0-9']+")

    @modal.method()
    def analyze(self, document: str) -> dict:
        words = [word.lower() for word in self.word_pattern.findall(document)]
        counter = Counter(words)
        return {
            "word_count": len(words),
            "unique_word_count": len(counter),
            "top_words": counter.most_common(3),
        }


@app.function(image=image, volumes={"/reports": volume})
def write_report(report: dict, report_path: str) -> str:
    import os

    os.makedirs("/reports", exist_ok=True)
    with open(report_path, "w", encoding="utf-8") as report_file:
        json.dump(report, report_file, indent=2)
    volume.commit()
    return report_path


@app.function(image=image)
def store_metrics(metrics: dict) -> None:
    output_dict.update(metrics)


@app.local_entrypoint()
def main() -> None:
    documents = [
        "Modal makes distributed computing simple for data processing workflows.",
        "Serverless pipelines scale when you need them and stay idle when you do not.",
        "Text analytics can uncover patterns in documents with word frequency stats.",
        "Python standard library tools like re and collections stay lightweight.",
        "Parallel document analysis keeps throughput high across batches of files.",
        "Repeatable analytics ensure metrics are consistent across teams.",
    ]

    analyzer = DocumentAnalyzer()
    results = list(analyzer.analyze.map(documents))

    per_document = [
        {"document_id": index, **result} for index, result in enumerate(results)
    ]

    total_documents = len(results)
    total_words = sum(result["word_count"] for result in results)
    avg_words_per_doc = total_words / total_documents if total_documents else 0.0

    report = {
        "summary": {
            "total_documents": total_documents,
            "total_words": total_words,
            "avg_words_per_doc": avg_words_per_doc,
        },
        "documents": per_document,
    }

    write_report.remote(report, REPORT_PATH)
    store_metrics.remote(
        {
            "total_documents": total_documents,
            "total_words": total_words,
            "avg_words_per_doc": avg_words_per_doc,
            "report_path": REPORT_PATH,
        }
    )
